import random

def bogo_sort(arr):
    while any(arr[i] > arr[i+1] for i in range(len(arr)-1)):
        random.shuffle(arr)
    return arr

if __name__ == "__main__":
    print(f"Sorted: {bogo_sort([3, 1, 2])}")
